            ax_volume.bar(hist.index, hist['Volume'], color=colors, alpha=0.6, width=0.8)
            ax_volume.set_ylabel('Volume', fontsize=10, fontweight='bold')
            ax_volume.grid(True, alpha=0.2, linestyle=':')
            ax_volume.set_facecolor('#FFFFFF')
            
            ax_info = fig.add_subplot(gs[2, 0])
            ax_info.axis('off')
            
            info_text = f"📊 CURRENT STATUS\n"
            info_text += f"{'='*35}\n"
            info_text += f"Current Price: ₹{stock['current_price']:.2f}\n"
            info_text += f"1 Week Change: {stock['change_1w']:+.2f}%\n"
            info_text += f"1 Month Change: {stock['change_1m']:+.2f}%\n\n"
            info_text += f"📈 TECHNICAL INDICATORS\n"
            info_text += f"{'='*35}\n"
            info_text += f"RSI: {signals['rsi']:.1f}\n"
            info_text += f"MACD: {signals['macd']:.2f}\n"
            info_text += f"ADX: {signals['adx']:.1f}\n"
            info_text += f"Bullish Signals: {signals['bullish_signals']}\n\n"
            info_text += f"💰 RECOMMENDATION\n"
            info_text += f"{'='*35}\n"
            info_text += f"Action: {signals['investment_timing']}\n"
            info_text += f"Risk Level: {signals['risk_level']}\n"
            info_text += f"Confidence: {signals['confidence_score']}%"
            
            ax_info.text(0.05, 0.95, info_text, transform=ax_info.transAxes,
                        fontsize=9, verticalalignment='top', fontfamily='monospace',
                        bbox=dict(boxstyle='round', facecolor='#E8F5E9', 
                                edgecolor='#86BC25', linewidth=2, pad=15))
            
            ax_plan = fig.add_subplot(gs[2, 1])
            ax_plan.axis('off')
            
            plan_text = f"📅 INVESTMENT PLAN\n"
            plan_text += f"{'='*35}\n"
            plan_text += f"Buy Date: {dates['entry_date'].strftime('%d %b %Y')}\n"
            plan_text += f"Exit Date: {dates['exit_date'].strftime('%d %b %Y')}\n"
            plan_text += f"Hold: {dates['holding_days']} days\n\n"
            plan_text += f"💵 INVESTMENT DETAILS\n"
            plan_text += f"{'='*35}\n"
            plan_text += f"Invest: ₹{allocation['investment_amount']:,.0f}\n"
            plan_text += f"Shares: {allocation['shares_to_buy']}\n"
            plan_text += f"Entry: ₹{signals['entry_point']:.2f}\n"
