    def create_excel_report(self):
        if not OPENPYXL_AVAILABLE:
            print("⚠️  Excel formatting not available. Creating basic CSV...")
            self.save_basic_csv()
            return
        
        if not self.top_stocks:
            print("⚠️  No stocks to save")
            return
        
        try:
            filename = os.path.join(self.output_folder, 
                                   f'Investment_Report_{self.today.strftime("%Y%m%d_%H%M")}.xlsx')
            
            wb = Workbook()
            
            ws_summary = wb.active
            ws_summary.title = "Portfolio Summary"
            
            ws_summary['A1'] = "HIGH CONFIDENCE STOCK INVESTMENT REPORT"
            ws_summary['A1'].font = Font(size=16, bold=True, color='FFFFFF')
            ws_summary['A1'].fill = PatternFill(start_color='86BC25', end_color='86BC25', fill_type='solid')
            ws_summary['A1'].alignment = Alignment(horizontal='center', vertical='center')
            ws_summary.merge_cells('A1:F1')
            ws_summary.row_dimensions[1].height = 30
            
            ws_summary['A3'] = f"Analysis Date: {self.today.strftime('%d %B %Y, %I:%M %p IST')}"
            ws_summary['A3'].font = Font(size=11, italic=True)
            ws_summary.merge_cells('A3:F3')
            
            total_investment = sum(s['allocation']['investment_amount'] for s in self.top_stocks)
            total_return = sum(s['allocation']['expected_return'] for s in self.top_stocks)
            avg_roi = (total_return / total_investment * 100) if total_investment > 0 else 0
            avg_confidence = sum(s['signals']['confidence_score'] for s in self.top_stocks) / len(self.top_stocks)
            avg_holding = sum(s['dates']['holding_days'] for s in self.top_stocks) / len(self.top_stocks)
            
            summary_data = [
                ['Total Investment Capital', f"₹{self.investment_capital:,.2f}"],
                ['Amount to Invest', f"₹{total_investment:,.2f}"],
                ['Expected Returns', f"₹{total_return:,.2f}"],
                ['Total Exit Value', f"₹{total_investment + total_return:,.2f}"],
                ['Portfolio ROI', f"{avg_roi:.2f}%"],
                ['Number of Stocks', len(self.top_stocks)],
                ['Average Confidence', f"{avg_confidence:.1f}%"],
                ['Average Holding Period', f"{avg_holding:.0f} days"],
                ['Minimum Confidence Threshold', f"{self.min_confidence}%"]
            ]
            
            start_row = 5
            for i, (label, value) in enumerate(summary_data, start=start_row):
                ws_summary[f'A{i}'] = label
                ws_summary[f'A{i}'].font = Font(bold=True)
                ws_summary[f'B{i}'] = value
                ws_summary[f'B{i}'].font = Font(size=11)
            
            for row in range(start_row, start_row + len(summary_data)):
                ws_summary[f'A{row}'].fill = PatternFill(start_color='E8F5E9', end_color='E8F5E9', fill_type='solid')
                ws_summary[f'B{row}'].fill = PatternFill(start_color='FFFFFF', end_color='FFFFFF', fill_type='solid')
            
            ws_summary.column_dimensions['A'].width = 30
            ws_summary.column_dimensions['B'].width = 25
            
            ws_details = wb.create_sheet(title="Investment Details")
            
            headers = ['Rank', 'Company Name', 'Symbol', 'Current Price', 'Confidence %', 
                      'Action', 'Risk Level', 'Buy Date', 'Exit Date', 'Hold Days',
                      'Invest Amount', 'Shares', 'Entry Price', 'Target Price', 'Stop Loss',
                      'Expected Return', 'ROI %', 'RSI', 'MACD', 'ADX', 'Reason']
            
            for col, header in enumerate(headers, start=1):
                cell = ws_details.cell(row=1, column=col, value=header)
                cell.font = Font(bold=True, color='FFFFFF', size=11)
                cell.fill = PatternFill(start_color='00A3E0', end_color='00A3E0', fill_type='solid')
                cell.alignment = Alignment(horizontal='center', vertical='center', wrap_text=True)
            
            for idx, stock in enumerate(self.top_stocks, start=2):
                signals = stock['signals']
                allocation = stock['allocation']
                dates = stock['dates']
                
                row_data = [
                    idx - 1,
                    stock['name'],
                    stock['symbol'].replace('.NS', ''),
                    f"₹{stock['current_price']:.2f}",
                    f"{signals['confidence_score']:.1f}%",
                    signals['investment_timing'],
                    signals['risk_level'],
                    dates['entry_date'].strftime('%d-%b-%Y'),
                    dates['exit_date'].strftime('%d-%b-%Y'),
                    dates['holding_days'],
                    f"₹{allocation['investment_amount']:,.2f}",
                    allocation['shares_to_buy'],
                    f"₹{signals['entry_point']:.2f}",
                    f"₹{signals['target_1']:.2f}",
                    f"₹{signals['stop_loss']:.2f}",
                    f"₹{allocation['expected_return']:,.2f}",
                    f"{allocation['roi_percentage']:.2f}%",
                    f"{signals['rsi']:.1f}",
                    f"{signals['macd']:.2f}",
                    f"{signals['adx']:.1f}",
                    signals['timing_reason']
                ]
                
                for col, value in enumerate(row_data, start=1):
                    cell = ws_details.cell(row=idx, column=col, value=value)
                    cell.alignment = Alignment(horizontal='left', vertical='center', wrap_text=True)
                    
                    if idx % 2 == 0:
                        cell.fill = PatternFill(start_color='F5F5F5', end_color='F5F5F5', fill_type='solid')
                    
                    if col == 5:
                        conf = signals['confidence_score']
                        if conf >= 85:
                            cell.fill = PatternFill(start_color='C8E6C9', end_color='C8E6C9', fill_type='solid')
                        elif conf >= 80:
                            cell.fill = PatternFill(start_color='FFF9C4', end_color='FFF9C4', fill_type='solid')
                    
                    if col == 6:
                        if value == 'BUY NOW':
                            cell.fill = PatternFill(start_color='A5D6A7', end_color='A5D6A7', fill_type='solid')
                            cell.font = Font(bold=True, color='1B5E20')
            
            for col in range(1, len(headers) + 1):
                ws_details.column_dimensions[ws_details.cell(row=1, column=col).column_letter].width = 15
            
            ws_details.column_dimensions['B'].width = 30
            ws_details.column_dimensions['U'].width = 40
            
            ws_dates = wb.create_sheet(title="Investment Calendar")
            
            ws_dates['A1'] = "INVESTMENT CALENDAR - ACTION DATES"
            ws_dates['A1'].font = Font(size=14, bold=True, color='FFFFFF')
            ws_dates['A1'].fill = PatternFill(start_color='FF9800', end_color='FF9800', fill_type='solid')
            ws_dates['A1'].alignment = Alignment(horizontal='center', vertical='center')
            ws_dates.merge_cells('A1:F1')
            ws_dates.row_dimensions[1].height = 25
            
            cal_headers = ['Rank', 'Stock', 'Action', 'Buy Date', 'Stop-Loss Review', 'Exit Date']
            for col, header in enumerate(cal_headers, start=1):
                cell = ws_dates.cell(row=3, column=col, value=header)
                cell.font = Font(bold=True, size=11)
                cell.fill = PatternFill(start_color='FFE0B2', end_color='FFE0B2', fill_type='solid')
                cell.alignment = Alignment(horizontal='center', vertical='center')
            
            sorted_stocks = sorted(self.top_stocks, key=lambda x: x['dates']['entry_date'])
            
            for idx, stock in enumerate(sorted_stocks, start=4):
                dates = stock['dates']
                signals = stock['signals']
                
                ws_dates[f'A{idx}'] = idx - 3
                ws_dates[f'B{idx}'] = stock['symbol'].replace('.NS', '')
                ws_dates[f'C{idx}'] = signals['investment_timing']
                ws_dates[f'D{idx}'] = dates['entry_date'].strftime('%d %B %Y (%A)')
                ws_dates[f'E{idx}'] = dates['stop_loss_check_date'].strftime('%d %B %Y')
                ws_dates[f'F{idx}'] = dates['exit_date'].strftime('%d %B %Y (%A)')
                
                for col in range(1, 7):
                    ws_dates.cell(row=idx, column=col).alignment = Alignment(horizontal='left', vertical='center')
                    if idx % 2 == 0:
                        ws_dates.cell(row=idx, column=col).fill = PatternFill(start_color='FFF8E1', 
                                                                               end_color='FFF8E1', fill_type='solid')
            
            ws_dates.column_dimensions['A'].width = 8
            ws_dates.column_dimensions['B'].width = 20
            ws_dates.column_dimensions['C'].width = 15
            ws_dates.column_dimensions['D'].width = 30
            ws_dates.column_dimensions['E'].width = 20
            ws_dates.column_dimensions['F'].width = 30
            
            wb.save(filename)
            print(f"\n✓ Professional Excel report saved: '{filename}'")
            return filename
            
        except Exception as e:
            print(f"✗ Error creating Excel: {str(e)}")
            return None
    
    def save_basic_csv(self):
        try:
            filename = os.path.join(self.output_folder, 
                                   f'investment_plan_{self.today.strftime("%Y%m%d_%H%M")}.csv')
            
            plan_data = []
            for stock in self.top_stocks:
                signals = stock['signals']
                allocation = stock['allocation']
                dates = stock['dates']
                
                plan_data.append({
                    'Rank': self.top_stocks.index(stock) + 1,
                    'Stock': stock['name'],
                    'Symbol': stock['symbol'].replace('.NS', ''),
                    'Confidence %': signals['confidence_score'],
                    'Current Price': f"₹{stock['current_price']:.2f}",
                    'Investment Action': signals['investment_timing'],
                    'Risk Level': signals['risk_level'],
                    'Buy Date': dates['entry_date'].strftime('%d-%b-%Y'),
                    'Exit Date': dates['exit_date'].strftime('%d-%b-%Y'),
                    'Holding Days': dates['holding_days'],
                    'Invest Amount': f"₹{allocation['investment_amount']:,.2f}",
                    'Shares': allocation['shares_to_buy'],
                    'Entry Price': f"₹{signals['entry_point']:.2f}",
                    'Stop Loss': f"₹{signals['stop_loss']:.2f}",
                    'Target': f"₹{signals['target_1']:.2f}",
                    'Expected Return': f"₹{allocation['expected_return']:,.2f}",
                    'ROI %': f"{allocation['roi_percentage']:.2f}%"
                })
            
            df = pd.DataFrame(plan_data)
            df.to_csv(filename, index=False)
            print(f"✓ CSV report saved: '{filename}'")
        except Exception as e:
            print(f"✗ Error saving CSV: {str(e)}")
    
    def generate_all_reports(self):
        if not self.top_stocks:
            print("\n⚠️  No high-confidence stocks found. No reports to generate.")
            return
        
        print(f"\n\n{'='*80}")
        print(f"GENERATING INDIVIDUAL STOCK INVESTMENT PLANS")
        print(f"{'='*80}\n")
        
        for idx, stock in enumerate(self.top_stocks, 1):
            print(f"Creating investment card {idx}/{len(self.top_stocks)}: {stock['name']}...", end=' ')
            chart_file = self.create_individual_stock_chart(stock, idx)
            if chart_file:
                print("✓")
            else:
                print("✗")
        
        print(f"\n{'='*80}")
        print(f"GENERATING EXCEL REPORT")
        print(f"{'='*80}\n")
        
        excel_file = self.create_excel_report()
        
        print(f"\n{'='*80}")
        print(f"ALL REPORTS GENERATED SUCCESSFULLY!")
        print(f"{'='*80}")
        print(f"\n📁 Output Folder: {self.output_folder}")
        print(f"   • Individual Investment Plans: {len(self.top_stocks)} PNG files")
        print(f"   • Excel Report: 1 XLSX file with 3 sheets")
        print(f"\nOpen the folder to view all investment plans and charts!")

